import React, { useState, useRef, useEffect } from 'react';

const ItemsSortDropdown = ({ itemSort, setItemSort }) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef(null);

  const sortOptions = [
    { value: 'title_asc', label: 'По алфавиту (А - Я)', icon: 'pi-sort-alpha-down' },
    { value: 'title_desc', label: 'По алфавиту (Я - А)', icon: 'pi-sort-alpha-up' },
    { value: 'price_asc', label: 'По возрастанию цены', icon: 'pi-sort-amount-up' },
    { value: 'price_desc', label: 'По убыванию цены', icon: 'pi-sort-amount-down' },
    { value: 'createdAt_desc', label: 'По дате добавления', icon: 'pi-calendar' },
    { value: 'priority_desc', label: 'По желанности', icon: 'pi-star' }
  ];

  const currentOption = sortOptions.find(opt => opt.value === itemSort) || sortOptions[4];

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div ref={dropdownRef} style={{ position: 'relative', width: '100%' }}>
      {/* Кнопка выпадающего списка */}
      <div
        onClick={() => setIsOpen(!isOpen)}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: '12px',
          padding: '10px 16px',
          borderRadius: '12px',
          border: '2px solid #18B700',
          backgroundColor: '#fff',
          cursor: 'pointer',
          height: '40px',
          position: 'relative'
        }}
      >
        <i className="pi pi-sort-alt" style={{ fontSize: '16px', color: '#1e293b' }}></i>
        <span style={{ fontSize: '14px', color: '#1e293b', flex: 1, fontWeight: '600' }}>{currentOption.label}</span>
        <i className="pi pi-chevron-down" style={{ fontSize: '12px', color: '#1e293b' }}></i>
      </div>

      {/* Выпадающий список */}
      {isOpen && (
        <div
          style={{
            position: 'absolute',
            top: '100%',
            left: 0,
            right: 0,
            marginTop: '4px',
            backgroundColor: '#fff',
            borderRadius: '12px',
            boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
            zIndex: 1000,
            overflow: 'hidden'
          }}
        >
          {sortOptions.map((option) => (
            <div
              key={option.value}
              onClick={() => {
                setItemSort(option.value);
                setIsOpen(false);
              }}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: '12px',
                padding: '12px 16px',
                cursor: 'pointer',
                backgroundColor: itemSort === option.value ? '#f0f9ff' : '#fff',
                transition: 'background-color 0.2s'
              }}
              onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f0f9ff'}
              onMouseLeave={(e) => e.currentTarget.style.backgroundColor = itemSort === option.value ? '#f0f9ff' : '#fff'}
            >
              <i className={`pi ${option.icon}`} style={{ fontSize: '16px', color: '#1e293b' }}></i>
              <span style={{ fontSize: '14px', color: '#1e293b', fontWeight: '600' }}>{option.label}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ItemsSortDropdown;
